changeSet.sql:
SET @reg_id = ( SELECT cr.id FROM competition_registrations cr JOIN competitions c ON c.id = cr.competition_id WHERE c.name = 'Stadtpark Halbmarathon 2026' AND cr.user_id = (SELECT id FROM users WHERE username = 'testuser') );
SET @plan_id = (SELECT id FROM training_plans WHERE name = 'Halbmarathon-Trainingsplan 1:26 h');
INSERT INTO user_training_entries (competition_registration_id, training_id, training_date, week_number, completed) SELECT @reg_id, t.id, DATE_ADD('2026-03-16', INTERVAL ( (t.week_number - 1) * 7 + CASE t.day_of_week WHEN 'MONDAY' THEN 0 WHEN 'TUESDAY' THEN 1 WHEN 'WEDNESDAY' THEN 2 WHEN 'THURSDAY' THEN 3 WHEN 'FRIDAY' THEN 4 WHEN 'SATURDAY' THEN 5 WHEN 'SUNDAY' THEN 6 END ) DAY), t.week_number, false FROM trainings t WHERE t.training_plan_id = @plan_id ORDER BY t.week_number, FIELD(t.day_of_week, 'MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY','SUNDAY');
